import React, { useEffect, useState } from "react";
import axios from "axios";

const LabourDashboard = () => {
  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/api/jobs/all")
      .then(res => setJobs(res.data));
  }, []);

  return (
    <div style={styles.container}>

      <h2>Jobs</h2>

      {jobs.map(j => (
        <div key={j._id} style={styles.card}>
          <h3>{j.workType}</h3>
          <p>{j.status}</p>

          <button onClick={() =>
            axios.put(`http://localhost:5000/api/jobs/accept/${j._id}`)
          }>Accept</button>

          <button onClick={() =>
            axios.put(`http://localhost:5000/api/jobs/reject/${j._id}`)
          }>Reject</button>
        </div>
      ))}

    </div>
  );
};

export default LabourDashboard;

const styles = {
  container: { background: "#0b1220", minHeight: "100vh", color: "white", padding: "20px" },

  card: { background: "#111a2e", padding: "15px", margin: "10px 0" }
};
